mapper.select:
SELECT t.id AS task_id, t.task_name, t.task_type, t.status, t.project_id, p.project_name, p.project_code, t.execute_mode, t.priority, t.planned_start, t.planned_end, CASE WHEN t.planned_end IS NOT NULL AND t.planned_end < CURDATE() AND t.status NOT IN ('COMPLETED', 'CONFIRMED') THEN 1 ELSE 0 END AS overdue FROM project_task t INNER JOIN project p ON p.id = t.project_id AND p.deleted = 0 INNER JOIN engineer e ON e.id = t.assignee_id AND e.deleted = 0 WHERE t.deleted = 0 AND e.user_id = #{userId}
AND t.status = #{status}
ORDER BY overdue DESC, t.planned_end ASC
LIMIT #{limit}

SELECT d.id AS deliverable_id, d.outsource_task_id, ot.task_id AS project_task_id, d.deliverable_type, d.file_name, d.file_url, d.remark, d.create_time AS submit_time, p.id AS project_id, p.project_name, t.task_name, ac.id AS agent_company_id, ac.company_name AS agent_company_name, ot.status AS outsource_status, ot.deadline FROM outsource_deliverable d INNER JOIN outsource_task ot ON ot.id = d.outsource_task_id AND ot.deleted = 0 INNER JOIN project_task t ON t.id = ot.task_id AND t.deleted = 0 INNER JOIN project p ON p.id = ot.project_id AND p.deleted = 0 LEFT JOIN agent_company ac ON ac.id = ot.agent_company_id AND ac.deleted = 0 WHERE d.deleted = 0 AND p.pm_id = #{userId}
AND ot.status = #{status}
ORDER BY d.create_time DESC
LIMIT #{limit}

SELECT COUNT(*) FROM project
WHERE deleted = 0 AND pm_id = #{userId}
  AND status NOT IN ('CLOSE', 'ARCHIVED', 'CANCELLED')

SELECT COUNT(*) FROM project_task t
INNER JOIN engineer e ON e.id = t.assignee_id AND e.deleted = 0
WHERE t.deleted = 0 AND e.user_id = #{userId}
  AND t.planned_end IS NOT NULL
  AND t.planned_end < #{today}
  AND t.status NOT IN ('COMPLETED', 'CONFIRMED')

SELECT COALESCE(SUM(ts.hours), 0)
FROM timesheet ts
INNER JOIN engineer e ON e.id = ts.engineer_id AND e.deleted = 0
WHERE ts.deleted = 0
  AND e.user_id = #{userId}
  AND ts.work_date >= #{startDay}
  AND ts.work_date <= #{endDay}

SELECT COUNT(*) FROM outsource_task ot
WHERE ot.deleted = 0
  AND ot.agent_company_id = #{agentCompanyId}

      AND ot.status = #{status}

SELECT ot.id AS outsource_task_id, ot.task_id AS project_task_id, t.task_name, ot.project_id, p.project_code, p.project_name, ot.agent_company_id, ac.company_name AS agent_company_name, ot.agent_engineer_id, ae.name AS agent_engineer_name, ot.status, ot.task_scope, ot.deadline, ot.submit_count, ot.create_time, CASE WHEN ot.deadline IS NOT NULL AND ot.deadline < CURDATE() AND ot.status NOT IN ('CONFIRMED', 'REJECTED') THEN 1 ELSE 0 END AS overdue FROM outsource_task ot INNER JOIN project_task t ON t.id = ot.task_id AND t.deleted = 0 INNER JOIN project p ON p.id = ot.project_id AND p.deleted = 0 LEFT JOIN agent_company ac ON ac.id = ot.agent_company_id AND ac.deleted = 0 LEFT JOIN agent_engineer ae ON ae.id = ot.agent_engineer_id AND ae.deleted = 0 WHERE ot.deleted = 0 AND ot.agent_company_id = #{agentCompanyId}
AND ot.status = #{status}
ORDER BY ot.create_time DESC
LIMIT #{limit}
